async (params, browser) => {
  // Open business page
  await browser.open(`${params.business_url}`)

  // Wait for page
  await browser.waitForSelector('h1, [class*=\'businessName\']', 15000)

  await browser.wait(2000)

  // Scroll to photos
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract photos
  const photos_data = await browser.evaluate(`const photos = []; const photoEls = document.querySelectorAll('[class*="photo-box"] img, [class*="biz-photos"] img, [class*="gallery"] img, [class*="photo-header"] img'); photoEls.forEach(function(img) { const src = img.getAttribute('src') || ''; const alt = img.getAttribute('alt') || ''; if (src && src.includes('yelp') && !photos.find(function(p) { return p.url === src; })) { const captionEl = img.closest('[class*="photo"]') ? img.closest('[class*="photo"]').querySelector('[class*="caption"], p') : null; photos.push({ url: src, alt: alt, caption: captionEl ? captionEl.textContent.trim() : '' }); } }); const totalPhotosEl = document.querySelector('[class*="photo-count"], a[href*="photos"]'); const nameEl = document.querySelector('h1'); return { business_name: nameEl ? nameEl.textContent.trim() : '', total_photos_text: totalPhotosEl ? totalPhotosEl.textContent.trim() : '', photo_count: photos.length, photos: photos.slice(0, 20), url: window.location.href }`)

  return photos_data
}
